import * as React from "react"
import {
  IconTruck,
  IconCalendarStats,
  IconClock,
  IconClipboardX,
  IconTool,
} from "@tabler/icons-react"
import {
  Header,
  HeaderBrand,
  HeaderActions,
  StatGroup,
  Badge,
  Card,
  CardHeader,
  CardTitle,
  CardDescription,
  CardContent,
} from "@gunjo/ui"
import type { ActionItem } from "@gunjo/ui"

import {
  OPERATOR,
  TODAY,
  VEHICLES,
  DRIVERS_HOS,
  BEHAVIOR,
  TENKO,
  MAINTENANCE_HISTORY,
  HOS_LIMITS,
} from "./data"
import { classifyExpiry } from "@gunjo/ui"
import { classifyLimit } from "./LimitMonitor"
import {
  InspectionTable,
  HoursOfServicePanel,
  BehaviorBoard,
  TenkoTable,
  MaintenanceTimeline,
  FleetStatusBoard,
  IssueQueue,
  ComplianceTabs,
} from "./sections"

/* ───────── サーバー側で集計（純粋関数のみ：classifyExpiry / classifyLimit） ───────── */

function buildSummary() {
  const shakenSoon = VEHICLES.filter((v) => {
    const s = classifyExpiry(v.shaken, { today: TODAY, warnWithinDays: 30 }).state
    return s === "expiring" || s === "expired"
  }).length

  const hosOver = DRIVERS_HOS.filter((d) => {
    const k = classifyLimit(d.kosokuToday, HOS_LIMITS.kosoku.soft, HOS_LIMITS.kosoku.hard, 0.9, false)
    const r = classifyLimit(d.renzokuMax, HOS_LIMITS.renzoku.soft, HOS_LIMITS.renzoku.hard, 0.9, false)
    const q = classifyLimit(d.kyusokuLast, HOS_LIMITS.kyusoku.soft, HOS_LIMITS.kyusoku.floor, 0.95, true)
    return [k, r, q].some((s) => s === "over-soft" || s === "over-hard")
  }).length

  const tenkoMissing = TENKO.filter((t) => t.status === "未実施").length
  const needsMaint = VEHICLES.filter((v) => v.maintenance === "要整備" || v.maintenance === "入庫中").length

  return { shakenSoon, hosOver, tenkoMissing, needsMaint }
}

function buildIssues(): ActionItem[] {
  const issues: ActionItem[] = []

  for (const v of VEHICLES) {
    const { state, days } = classifyExpiry(v.shaken, { today: TODAY, warnWithinDays: 30 })
    if (state === "expired") {
      issues.push({
        id: `shaken-${v.id}`,
        severity: "critical",
        kind: "車検失効",
        title: `${v.unit}（${v.plate}）の車検が失効`,
        detail: `継続検査の有効期限を ${Math.abs(days ?? 0)}日 超過。運行停止・即時手配が必要。`,
        meta: v.shaken.replace(/-/g, "/"),
      })
    } else if (state === "expiring") {
      issues.push({
        id: `shaken-${v.id}`,
        severity: "warning",
        kind: "車検間近",
        title: `${v.unit} の車検が ${days}日後に満了`,
        detail: "継続検査の予約・整備入庫を手配してください。",
        meta: v.shaken.replace(/-/g, "/"),
      })
    }
  }

  for (const d of DRIVERS_HOS) {
    const k = classifyLimit(d.kosokuToday, HOS_LIMITS.kosoku.soft, HOS_LIMITS.kosoku.hard, 0.9, false)
    if (k === "over-hard") {
      issues.push({
        id: `hos-k-${d.id}`,
        severity: "critical",
        kind: "拘束時間超過",
        title: `${d.name}：当日拘束 ${d.kosokuToday}h（最大16h 超過）`,
        detail: "改善基準告示の最大拘束時間を超過。乗務交代・運行見直しが必要。",
        meta: d.unit,
      })
    } else if (k === "over-soft") {
      issues.push({
        id: `hos-k-${d.id}`,
        severity: "warning",
        kind: "拘束時間注意",
        title: `${d.name}：当日拘束 ${d.kosokuToday}h（基準13h 超過）`,
        detail: "基準拘束時間13hを超過。延長は週2回・月の上限に注意。",
        meta: d.unit,
      })
    }
    const q = classifyLimit(d.kyusokuLast, HOS_LIMITS.kyusoku.soft, HOS_LIMITS.kyusoku.floor, 0.95, true)
    if (q === "over-hard") {
      issues.push({
        id: `hos-q-${d.id}`,
        severity: "critical",
        kind: "休息不足",
        title: `${d.name}：休息 ${d.kyusokuLast}h（下限9h 未満）`,
        detail: "継続11h（下限9h）を確保できていません。次回乗務までに是正。",
        meta: d.unit,
      })
    }
  }

  for (const t of TENKO) {
    if (t.status === "未実施") {
      issues.push({
        id: `tenko-${t.id}`,
        severity: "critical",
        kind: "点呼未実施",
        title: `${t.driver}（${t.unit}）の点呼・アルコールチェック未実施`,
        detail: `${t.kind}を未実施のまま。乗務前点呼を完了させてください。`,
        meta: "本日",
      })
    } else if (t.alcohol != null && t.alcohol > 0) {
      issues.push({
        id: `alc-${t.id}`,
        severity: "warning",
        kind: "アルコール検出",
        title: `${t.driver}：アルコール ${t.alcohol.toFixed(2)} mg/L 検出`,
        detail: "酒気帯びの疑い。乗務可否を再判定してください。",
        meta: t.time ?? "—",
      })
    }
  }

  for (const v of VEHICLES) {
    if (v.maintenance === "要整備") {
      issues.push({
        id: `maint-${v.id}`,
        severity: "warning",
        kind: "要整備",
        title: `${v.unit}：要整備フラグ`,
        detail: "日常点検で不具合あり。整備入庫を手配してください。",
        meta: v.unit,
      })
    }
  }

  return issues
}

export default function TruckCompliancePage() {
  const summary = buildSummary()
  const issues = buildIssues()

  return (
    <div className="min-h-screen bg-muted/20 text-foreground">
      {/* デスクトップ用の上部クロム（Header は desktop chrome、PageHeader は phone 用なので不採用） */}
      <Header className="sticky top-0 z-30">
        <HeaderBrand>
