            <IconTruck className="size-5" aria-hidden="true" />
          </span>
          <div className="min-w-0">
            <div className="truncate text-sm font-semibold">{OPERATOR.company} 車両・労務コンプライアンス管理</div>
            <div className="truncate text-xs text-muted-foreground">
              {OPERATOR.office}・{OPERATOR.garage}
            </div>
          </div>
        </HeaderBrand>
        <HeaderActions>
          <Badge variant="outline">{OPERATOR.manager}</Badge>
          <Badge variant="secondary">本日 {TODAY.replace(/-/g, "/")}</Badge>
        </HeaderActions>
      </Header>

      <main className="mx-auto flex w-full max-w-[1400px] flex-col gap-6 p-4 sm:p-6">
        {/* KPI サマリ */}
        <section aria-label="コンプライアンス サマリ">
          <StatGroup
            cols={{ base: 2, md: 4 }}
            items={[
              {
                label: "車検期限が近い車両",
                value: `${summary.shakenSoon} 台`,
                hint: "30日以内 / 失効",
                trend: summary.shakenSoon > 0 ? "up" : "flat",
                tone: summary.shakenSoon > 0 ? "negative" : "neutral",
              },
              {
                label: "拘束時間オーバー",
                value: `${summary.hosOver} 名`,
                hint: "改善基準告示 基準超過",
                trend: summary.hosOver > 0 ? "up" : "flat",
                tone: summary.hosOver > 0 ? "negative" : "neutral",
              },
              {
                label: "点呼未実施",
                value: `${summary.tenkoMissing} 件`,
                hint: "本日の乗務前点呼",
                trend: summary.tenkoMissing > 0 ? "up" : "flat",
                tone: summary.tenkoMissing > 0 ? "negative" : "neutral",
              },
              {
                label: "要整備 / 入庫中",
                value: `${summary.needsMaint} 台`,
                hint: "整備フラグ",
                trend: "flat",
                tone: summary.needsMaint > 0 ? "negative" : "neutral",
              },
            ]}
          />
        </section>

        {/* 要対応キュー + 車両ステータス盤 */}
        <section className="grid grid-cols-1 gap-6 xl:grid-cols-[minmax(0,1.4fr)_minmax(0,1fr)]">
          <Card className="p-4">
            <CardHeader className="p-0 pb-3">
              <CardTitle as="h2" className="flex items-center gap-2 text-base">
                <IconClipboardX className="size-5 text-destructive" aria-hidden="true" />
                要対応（{issues.length}件）
              </CardTitle>
              <CardDescription>車検切れ間近・拘束時間オーバー・点呼未実施・整備期限を優先度順に表示</CardDescription>
            </CardHeader>
            <CardContent className="p-0">
              <IssueQueue items={issues} />
            </CardContent>
          </Card>

          <Card className="p-4">
            <CardHeader className="p-0 pb-3">
              <CardTitle as="h2" className="flex items-center gap-2 text-base">
                <IconTruck className="size-5 text-muted-foreground" aria-hidden="true" />
                車両ステータス盤
              </CardTitle>
              <CardDescription>{VEHICLES.length}台・故障/期限切れを上位表示</CardDescription>
            </CardHeader>
            <CardContent className="p-0">
              <FleetStatusBoard vehicles={VEHICLES} />
            </CardContent>
          </Card>
        </section>

        {/* メインのタブ領域 */}
        <section aria-label="コンプライアンス詳細">
          <Card className="p-4">
            <ComplianceTabs
              inspection={
                <div className="flex flex-col gap-3">
                  <div className="flex flex-wrap items-center gap-2 text-sm text-muted-foreground">
                    <IconCalendarStats className="size-4" aria-hidden="true" />
                    車検（継続検査）有効期限と次回点検。期限間近・超過を行で判定。
                  </div>
                  <InspectionTable vehicles={VEHICLES} />
                </div>
              }
              hos={
                <div className="flex flex-col gap-3">
                  <div className="flex flex-wrap items-center gap-2 text-sm text-muted-foreground">
                    <IconClock className="size-4" aria-hidden="true" />
                    改善基準告示：拘束13h（最大16h）・連続運転4h・休息11h（下限9h）に対する当日実績。
                  </div>
                  <HoursOfServicePanel drivers={DRIVERS_HOS} />
                </div>
              }
              behavior={<BehaviorBoard drivers={BEHAVIOR} />}
              tenko={
                <div className="flex flex-col gap-3">
                  <div className="flex flex-wrap items-center gap-2 text-sm text-muted-foreground">
                    <IconTool className="size-4" aria-hidden="true" />
                    対面 / IT / 電話点呼とアルコール測定値（0.00 mg/L 合格）・健康状態の記録。
                  </div>
                  <TenkoTable records={TENKO} />
                </div>
              }
            />
          </Card>
        </section>

        {/* 整備履歴 / 入庫予定 */}
        <section aria-label="整備履歴">
          <MaintenanceTimeline events={MAINTENANCE_HISTORY} />
        </section>
      </main>
    </div>
  )
}

/**
 * LimitMonitor — 「測定値 vs 名前付きの法定限度（near/over 状態つき）」を表す合成プリミティブ。
 *
 * なぜ手組み（合成）なのか：
 *   @gunjo/ui には「値 vs 容量」(Meter) と「値 vs 基準範囲 H/L」(ReferenceValue) はあるが、
 *   改善基準告示のような「名前付きの“ソフト上限／ハード上限”に対する超過判定」を、
 *   ・限度を 0–max のうちの一分数として線で描く
 *   ・ソフト超過（要注意）とハード超過（違反）を別状態で出し分ける
 *   ・色だけに依存しない状態ラベル（基準内 / 上限間近 / 基準超過 / 上限超過）を付ける
 *   という形で1つにまとめたコンポーネントは無い。Meter の target は higher-is-worse では
 *   「視覚的参照線」止まりで tone を駆動しないため、超過状態は呼び出し側で判定する必要がある。
 *
 * そこで Meter を track として再利用しつつ、限度判定ロジックと状態 chip を被せている。
 */

import * as React from "react"
import {
  IconCircleCheck,
  IconAlertTriangle,
  IconCircleX,
} from "@tabler/icons-react"
import { Meter, type MeterTone, cn } from "@gunjo/ui"

export type LimitState = "ok" | "near" | "over-soft" | "over-hard"

const STATE_CONFIG: Record<
  LimitState,
  { label: string; chip: string; tone: MeterTone; Icon: typeof IconCircleCheck }
> = {
  ok: { label: "基準内", chip: "bg-success-subtle text-success", tone: "success", Icon: IconCircleCheck },
  near: { label: "上限間近", chip: "bg-warning-subtle text-warning", tone: "warning", Icon: IconAlertTriangle },
  "over-soft": { label: "基準超過", chip: "bg-warning-subtle text-warning", tone: "warning", Icon: IconAlertTriangle },
  "over-hard": { label: "上限超過", chip: "bg-destructive-subtle text-destructive", tone: "destructive", Icon: IconCircleX },
}

export interface LimitMonitorProps {
  /** 測定値 */
  value: number
  /** ソフト上限（基準値）。超えると「基準超過」 */
  soft: number
  /** ハード上限（最大）。超えると「上限超過＝違反」。省略時は soft と同じ */
  hard?: number
  /** バーの最大値。省略時は hard*1.15（限度線が右端に張り付かないように余白を取る） */
  max?: number
  /** 単位（"時間" など） */
  unit?: string
  /** ソフト上限に対する near の割合（0–1）。Default 0.9（=90%で「上限間近」） */
  nearFraction?: number
  /** 限度の呼称（"拘束13時間" など）— ラベルに使う */
  limitLabel: React.ReactNode
  /** アクセシブルネーム（行・指標の名前） */
  label: React.ReactNode
  /**
   * 「高いほど良い」指標（休息期間）。soft を下回ると near/over を逆向きに判定する。
   * Default false（高いほど悪い：拘束・連続運転）
   */
  higherIsBetter?: boolean
  /** 値の整形 */
  formatValue?: (v: number) => string
  className?: string
}

/** 純粋な限度判定（テーブルのセル着色などからも使えるよう export）。 */
export function classifyLimit(
  value: number,
  soft: number,
  hard: number,
  nearFraction: number,
  higherIsBetter: boolean
): LimitState {
  if (higherIsBetter) {
    // 休息期間：soft(=11h) 以上で基準内、hard(=下限9h) 未満は違反
    if (value < hard) return "over-hard"
    if (value < soft) return "over-soft"
    if (value < soft / nearFraction) return "near" // soft を少し上回る程度＝間近
    return "ok"
  }
  if (value > hard) return "over-hard"
  if (value > soft) return "over-soft"
  if (value >= soft * nearFraction) return "near"
  return "ok"
}

export function LimitMonitor({
  value,
  soft,
  hard = soft,
  max,
  unit = "",
  nearFraction = 0.9,
  limitLabel,
  label,
  higherIsBetter = false,
  formatValue,
  className,
}: LimitMonitorProps) {
  const fmt = React.useCallback(
    (v: number) => (formatValue ? formatValue(v) : `${Math.round(v * 10) / 10}${unit}`),
    [formatValue, unit]
  )
  const resolvedMax = max ?? (higherIsBetter ? Math.max(soft, value) * 1.1 : hard * 1.15)
  const state = classifyLimit(value, soft, hard, nearFraction, higherIsBetter)
  const cfg = STATE_CONFIG[state]
  const Icon = cfg.Icon

  // 超過量 / 残量
  const deltaText =
    !higherIsBetter && value > soft
      ? `${fmt(value - soft)} 超過`
      : higherIsBetter && value < soft
        ? `あと ${fmt(soft - value)}`
        : !higherIsBetter
          ? `残 ${fmt(Math.max(0, soft - value))}`
          : null

  return (
    <div className={cn("flex flex-col gap-1", className)}>
      <div className="flex items-center justify-between gap-2">
        <span className="flex items-center gap-1.5 text-sm">
          <span
            className={cn(
              "inline-flex items-center gap-1 rounded px-1.5 py-0.5 text-xs font-medium",
              cfg.chip
            )}
          >
            <Icon className="size-3.5" aria-hidden="true" />
            {cfg.label}
          </span>
          <span className="text-xs text-muted-foreground">{limitLabel}</span>
        </span>
        <span className={cn("text-sm font-semibold tabular-nums", cfg.tone === "destructive" ? "text-destructive" : cfg.tone === "warning" ? "text-warning" : "text-foreground")}>
          {fmt(value)}
          {deltaText ? <span className="ml-1 text-xs font-normal text-muted-foreground">（{deltaText}）</span> : null}
        </span>
      </div>
      {/* Meter を track として再利用。tone は限度判定で固定、target で限度線を描く。 */}
      <Meter
        value={value}
        max={resolvedMax}
        target={soft}
        tone={cfg.tone}
        label={label}
        showValue={false}
        valueText={`${fmt(value)}（上限 ${fmt(soft)}${hard !== soft ? `・最大 ${fmt(hard)}` : ""}）: ${cfg.label}`}
        size="sm"
      />
    </div>
  )
}

"use client"

import * as React from "react"
import {
  IconTruck,
  IconSnowflake,
  IconWind,
  IconBox,
  IconLayoutGrid,
  IconCircleCheck,
  IconAlertTriangle,
  IconTool,
  IconBuildingFactory2,
  IconClipboardCheck,
  IconPhone,
  IconDeviceLaptop,
  IconUserCheck,
  IconCircleX,
} from "@tabler/icons-react"
import type { ColumnDef } from "@tanstack/react-table"
import {
  ActionDataTable,
  ActionQueue,
  type ActionItem,
  Badge,
  Card,
  CardContent,
  CardHeader,
  CardTitle,
  CardDescription,
  DataTable,
  ExpiryBadge,
  classifyExpiry,
  Leaderboard,
  type LeaderboardItem,
  ReferenceValue,
  StatusBoard,
  type StatusBoardItem,
  Timeline,
  TimelineItem,
  TimelineTitle,
  TimelineDescription,
  TimelineTime,
  Tabs,
  TabsList,
  TabsTrigger,
  TabsContent,
  Button,
} from "@gunjo/ui"
import {
  TODAY,
  HOS_LIMITS,
  type Vehicle,
  type DriverHos,
  type DriverBehavior,
  type TenkoRecord,
  type MaintenanceEvent,
} from "./data"
import { LimitMonitor, classifyLimit } from "./LimitMonitor"

const BODY_ICON: Record<Vehicle["body"], React.ReactNode> = {
  冷凍: <IconSnowflake className="size-4" />,
  ウイング: <IconWind className="size-4" />,
  平ボディ: <IconLayoutGrid className="size-4" />,
  コンテナ: <IconBox className="size-4" />,
}

/* ───────────────────── 車検・点検期限テーブル ───────────────────── */

export function InspectionTable({ vehicles }: { vehicles: Vehicle[] }) {
  const columns = React.useMemo<ColumnDef<Vehicle>[]>(
    () => [
      {
        accessorKey: "unit",
        header: "号車 / 車両番号",
        cell: ({ row }) => (
          <div className="flex items-center gap-2">
            <IconTruck className="size-4 shrink-0 text-muted-foreground" aria-hidden="true" />
            <div className="min-w-0">
              <div className="font-medium text-foreground">{row.original.unit}</div>
              <div className="truncate text-xs text-muted-foreground tabular-nums">{row.original.plate}</div>
            </div>
          </div>
        ),
      },
      {
        accessorKey: "vehicleClass",
        header: "車種",
        size: 120,
        cell: ({ row }) => (
          <span className="inline-flex items-center gap-1 text-sm">
            {row.original.vehicleClass}
            <span className="inline-flex items-center gap-0.5 text-xs text-muted-foreground">
              {BODY_ICON[row.original.body]}
              {row.original.body}
            </span>
          </span>
        ),
      },
      {
        accessorKey: "shaken",
        header: "車検有効期限",
        size: 220,
        // 期日が早い順に並ぶよう、ソートは日付文字列で
        sortingFn: "alphanumeric",
        cell: ({ row }) => <ExpiryBadge value={row.original.shaken} today={TODAY} warnWithinDays={30} />,
      },
      {
        accessorKey: "nextInspection",
        header: "次回点検",
        size: 230,
        sortingFn: "alphanumeric",
        cell: ({ row }) => (
          <div className="flex flex-col gap-0.5">
            <ExpiryBadge value={row.original.nextInspection} today={TODAY} warnWithinDays={14} />
            <span className="text-xs text-muted-foreground">{row.original.inspectionKind}</span>
          </div>
        ),
      },
      {
        accessorKey: "maintenance",
        header: "整備",
        size: 110,
        cell: ({ row }) => {
          const m = row.original.maintenance
          return m === "要整備" ? (
            <Badge variant="warning" icon={<IconTool />}>要整備</Badge>
          ) : m === "入庫中" ? (
            <Badge variant="info" icon={<IconBuildingFactory2 />}>入庫中</Badge>
          ) : (
            <Badge variant="success" icon={<IconCircleCheck />}>正常</Badge>
          )
        },
      },
      {
        accessorKey: "odometer",
        header: "走行距離",
        size: 120,
        cell: ({ row }) => (
          <span className="tabular-nums text-sm text-muted-foreground">{row.original.odometer.toLocaleString()} km</span>
        ),
      },
    ],
    []
  )

  return (
    <ActionDataTable
      columns={columns}
      data={vehicles}
      getRowId={(v) => v.id}
      getRowLabel={(v) => `${v.unit}（${v.plate}）`}
      pageSize={10}
      enableSelection
      rowActions={[
        { id: "detail", label: "詳細", icon: IconClipboardCheck, onSelect: () => {} },
        { id: "shop", label: "入庫手配", icon: IconTool, onSelect: () => {} },
      ]}
      bulkActions={[
        { id: "notify", label: "車検案内を送付", icon: IconClipboardCheck, onSelect: () => {} },
      ]}
