/* ─────────────── 改善基準告示・拘束時間モニタ（HOS） ─────────────── */

function hoursFmt(v: number) {
  return `${Math.round(v * 10) / 10}h`
}

export function HoursOfServicePanel({ drivers }: { drivers: DriverHos[] }) {
  // 違反/要注意を上に
  const sorted = React.useMemo(() => {
    const sev = (d: DriverHos) => {
      const states = [
        classifyLimit(d.kosokuToday, HOS_LIMITS.kosoku.soft, HOS_LIMITS.kosoku.hard, 0.9, false),
        classifyLimit(d.renzokuMax, HOS_LIMITS.renzoku.soft, HOS_LIMITS.renzoku.hard, 0.9, false),
        classifyLimit(d.kyusokuLast, HOS_LIMITS.kyusoku.soft, HOS_LIMITS.kyusoku.floor, 0.95, true),
      ]
      if (states.includes("over-hard")) return 0
      if (states.includes("over-soft")) return 1
      if (states.includes("near")) return 2
      return 3
    }
    return [...drivers].sort((a, b) => sev(a) - sev(b))
  }, [drivers])

  return (
    <div className="grid grid-cols-1 gap-3 lg:grid-cols-2">
      {sorted.map((d) => {
        const monthState = classifyLimit(d.kosokuMonth, HOS_LIMITS.monthly.soft, HOS_LIMITS.monthly.hard, 0.92, false)
        return (
          <Card key={d.id} className="p-4">
            <div className="mb-3 flex items-center justify-between gap-2">
              <div>
                <div className="font-semibold text-foreground">{d.name}</div>
                <div className="text-xs text-muted-foreground">{d.unit} 乗務</div>
              </div>
              <Badge variant={monthState === "over-hard" || monthState === "over-soft" ? "destructive" : monthState === "near" ? "warning" : "outline"}>
                当月拘束 {hoursFmt(d.kosokuMonth)} / {HOS_LIMITS.monthly.soft}h
              </Badge>
            </div>
            <div className="flex flex-col gap-3">
              <LimitMonitor
                label={`${d.name} 当日の拘束時間`}
                limitLabel={`拘束 上限${HOS_LIMITS.kosoku.soft}h（最大${HOS_LIMITS.kosoku.hard}h）`}
                value={d.kosokuToday}
                soft={HOS_LIMITS.kosoku.soft}
                hard={HOS_LIMITS.kosoku.hard}
                unit="時間"
                formatValue={hoursFmt}
              />
              <LimitMonitor
                label={`${d.name} 連続運転時間`}
                limitLabel={`連続運転 ${HOS_LIMITS.renzoku.soft}h（30分中断）`}
                value={d.renzokuMax}
                soft={HOS_LIMITS.renzoku.soft}
                hard={HOS_LIMITS.renzoku.soft}
                unit="時間"
                formatValue={hoursFmt}
              />
              <LimitMonitor
                label={`${d.name} 休息期間`}
                limitLabel={`休息 ${HOS_LIMITS.kyusoku.soft}h（下限${HOS_LIMITS.kyusoku.floor}h）`}
                value={d.kyusokuLast}
                soft={HOS_LIMITS.kyusoku.soft}
                hard={HOS_LIMITS.kyusoku.floor}
                unit="時間"
                higherIsBetter
                formatValue={hoursFmt}
              />
            </div>
          </Card>
        )
      })}
    </div>
  )
}

/* ─────────────── デジタコ運転傾向（Leaderboard） ─────────────── */

export function BehaviorBoard({ drivers }: { drivers: DriverBehavior[] }) {
  const items = React.useMemo<LeaderboardItem[]>(
    () =>
      drivers.map((d) => ({
        id: d.id,
        label: d.name,
        sublabel: d.unit,
        value: d.score,
        fraction: d.score / 100,
        delta: d.deltaScore,
        tone: d.score >= 85 ? "success" : d.score >= 70 ? "warning" : "destructive",
        valueLabel: <span className="tabular-nums">{d.score}点</span>,
        trailing: (
          <span className="hidden items-center gap-2 text-xs text-muted-foreground tabular-nums sm:flex">
            <span title="急加速">急加 {d.kyukasoku}</span>
            <span title="急減速">急減 {d.kyugensoku}</span>
            <span title="速度超過" className={d.sokudo > 0 ? "text-destructive" : ""}>速超 {d.sokudo}</span>
            <span title="アイドリング（分）">ｱｲﾄﾞﾙ {d.idling}分</span>
          </span>
        ),
      })),
    [drivers]
  )

  return (
    <Card className="p-4">
      <CardHeader className="p-0 pb-3">
        <CardTitle as="h3" className="text-base">エコ・安全運転スコア（週間ランキング）</CardTitle>
        <CardDescription>デジタコ運行記録より集計。スコアが低い順に指導対象。</CardDescription>
      </CardHeader>
      <CardContent className="p-0">
        {/* 良い順に表示。delta は「上昇=良い」既定のまま（スコアは高いほど良い） */}
        <Leaderboard
          label="エコ・安全運転スコア ランキング"
          items={items}
          highlightTop={3}
          formatDelta={(n) => `${n > 0 ? "+" : ""}${n}`}
