/* ─────────────── 車両ステータス盤（StatusBoard） ─────────────── */

export function FleetStatusBoard({ vehicles }: { vehicles: Vehicle[] }) {
  const items = React.useMemo<StatusBoardItem[]>(
    () =>
      vehicles.map((v) => {
        const shaken = classifyExpiry(v.shaken, { today: TODAY, warnWithinDays: 30 })
        const tone =
          v.maintenance === "要整備" || shaken.state === "expired"
            ? "danger"
            : v.maintenance === "入庫中" || shaken.state === "expiring"
              ? "warning"
              : "success"
        const status =
          shaken.state === "expired"
            ? "車検切れ"
            : v.maintenance === "要整備"
              ? "要整備"
              : v.maintenance === "入庫中"
                ? "入庫中"
                : shaken.state === "expiring"
                  ? "車検間近"
                  : "稼働中"
        return {
          id: v.id,
          label: v.unit,
          status,
          tone,
          statusIcon:
            tone === "danger" ? <IconCircleX className="size-3.5" /> : tone === "warning" ? <IconAlertTriangle className="size-3.5" /> : <IconCircleCheck className="size-3.5" />,
          location: `${v.vehicleClass}・${v.body}`,
          note: `車検 ${v.shaken.replace(/-/g, "/")}`,
          icon: <IconTruck className="size-4" />,
        }
      }),
    [vehicles]
  )

  return <StatusBoard items={items} minTileWidth={170} />
}

